// DecodeDeleteRequest returns a decoder for requests sent to the collections
// delete endpoint.
func DecodeDeleteRequest(mux goahttp.Muxer, decoder func(*http.Request) goahttp.Decoder) func(*http.Request) (*collections.DeletePayload, error) {
	return func(r *http.Request) (*collections.DeletePayload, error) {
		var payload *collections.DeletePayload
		var (
			collectionID string
			sessionToken *string
			apikeyToken  *string
			err          error
		)
		collectionID = r.URL.Query().Get("collection_id")
		if collectionID == "" {
			err = goa.MergeErrors(err, goa.MissingFieldError("collection_id", "query string"))
		}
		err = goa.MergeErrors(err, goa.ValidateFormat("collection_id", collectionID, goa.FormatUUID))
		sessionTokenRaw := r.Header.Get("Gram-Session")
		if sessionTokenRaw != "" {
			sessionToken = &sessionTokenRaw
		}
		apikeyTokenRaw := r.Header.Get("Gram-Key")
		if apikeyTokenRaw != "" {
			apikeyToken = &apikeyTokenRaw
		}
		if err != nil {
			return payload, err
		}
		payload = NewDeletePayload(collectionID, sessionToken, apikeyToken)
		if payload.SessionToken != nil {
			if strings.Contains(*payload.SessionToken, " ") {
				// Remove authorization scheme prefix (e.g. "Bearer")
				cred := strings.SplitN(*payload.SessionToken, " ", 2)[1]
				payload.SessionToken = &cred
			}
		}
		if payload.ApikeyToken != nil {
			if strings.Contains(*payload.ApikeyToken, " ") {
				// Remove authorization scheme prefix (e.g. "Bearer")
				cred := strings.SplitN(*payload.ApikeyToken, " ", 2)[1]
				payload.ApikeyToken = &cred
			}
		}

		return payload, nil
	}
}

